 1	import React, { FC } from 'react';
 2	
 3	import { V1VirtualMachine, V1VirtualMachineInstance } from '@kubevirt-ui/kubevirt-api/kubevirt';
 4	import DiskListTitle from '@kubevirt-utils/components/DiskListTitle/DiskListTitle';
 5	import DiskSourceSelect from '@kubevirt-utils/components/DiskModal/components/DiskSourceSelect/DiskSourceSelect';
 6	import DiskModal from '@kubevirt-utils/components/DiskModal/DiskModal';
 7	import { SourceTypes } from '@kubevirt-utils/components/DiskModal/utils/types';
 8	import { useModal } from '@kubevirt-utils/components/ModalProvider/ModalProvider';
 9	import WindowsDrivers from '@kubevirt-utils/components/WindowsDrivers/WindowsDrivers';
10	import useDisksTableData from '@kubevirt-utils/resources/vm/hooks/disk/useDisksTableData';
11	import useProvisioningPercentage from '@kubevirt-utils/resources/vm/hooks/useProvisioningPercentage';
12	import {
13	  ListPageFilter,
14	  useListPageFilter,
15	  VirtualizedTable,
16	} from '@openshift-console/dynamic-plugin-sdk';
17	import { Flex, FlexItem } from '@patternfly/react-core';
18	import { updateDisks } from '@virtualmachines/details/tabs/configuration/details/utils/utils';
19	
20	import useDiskColumns from '../../hooks/useDiskColumns';
21	import useDisksFilters from '../../hooks/useDisksFilters';
22	
23	import DiskRow from './DiskRow';
24	
25	import './disklist.scss';
26	
27	type DiskListProps = {
28	  customize?: boolean;
29	  onDiskUpdate?: (updatedVM: V1VirtualMachine) => Promise<V1VirtualMachine>;
30	  vm: V1VirtualMachine;
31	  vmi?: V1VirtualMachineInstance;
32	};
33	
34	const DiskList: FC<DiskListProps> = ({ customize = false, onDiskUpdate, vm, vmi }) => {
35	  const { createModal } = useModal();
36	  const columns = useDiskColumns();
37	  const [disks, sourcesLoaded, loadError] = useDisksTableData(vm, vmi);
38	  const filters = useDisksFilters();
39	  const [data, filteredData, onFilterChange] = useListPageFilter(disks, filters);
40	
41	  const { percentages: provisioningPercentages } = useProvisioningPercentage(vm);
42	
43	  const onSubmit = onDiskUpdate || updateDisks;
44	
45	  return (
46	    <div className="kv-configuration-vm-disk-list">
47	      <DiskListTitle />
48	      <DiskSourceSelect
49	        onSelect={(diskSource: SourceTypes) => {
50	          return createModal(({ isOpen, onClose }) => (
51	            <DiskModal
52	              createDiskSource={diskSource}
53	              isOpen={isOpen}
54	              onClose={onClose}
55	              onSubmit={onDiskUpdate || updateDisks}
56	              vm={vm}
57	            />
58	          ));
59	        }}
60	      />
61	      <Flex>
62	        <FlexItem>
63	          <ListPageFilter
64	            data={data}
65	            hideLabelFilter
66	            loaded
67	            onFilterChange={onFilterChange}
68	            rowFilters={filters}
69	          />
70	        </FlexItem>
71	
72	        <FlexItem>
73	          <WindowsDrivers updateVM={onSubmit} vm={vm} />
74	        </FlexItem>
75	      </Flex>
76	      <VirtualizedTable
77	        columns={columns}
78	        data={filteredData}
79	        loaded
80	        loadError={loadError}
81	        Row={DiskRow}
82	        rowData={{ customize, onSubmit, provisioningPercentages, sourcesLoaded, vm, vmi }}
83	        unfilteredData={data}
84	      />
85	    </div>
86	  );
87	};
88	
89	export default DiskList;

